using System;using System.Collections.Generic;using System.IO;using System.Reflection;namespace BgCommon.UI.Designer.Plugins{    /// <summary>    /// 插件管理器    /// </summary>    public class PluginManager    {        private readonly ICSharpCode.WpfDesign.DesignContext _context;        private readonly List<IUIComponentPlugin> _plugins = new List<IUIComponentPlugin>();        private readonly Dictionary<string, List<Type>> _componentRegistry = new Dictionary<string, List<Type>>();                /// <summary>        /// 插件集合        /// </summary>        public IReadOnlyList<IUIComponentPlugin> Plugins => _plugins.AsReadOnly();                /// <summary>        /// 组件注册表        /// </summary>        public IReadOnlyDictionary<string, List<Type>> ComponentRegistry => _componentRegistry;                /// <summary>        /// 构造函数        /// </summary>        /// <param name="context">设计上下文</param>        public PluginManager(ICSharpCode.WpfDesign.DesignContext context)        {            _context = context;        }                /// <summary>        /// 发现插件        /// </summary>        /// <param name="pluginDirectory">插件目录</param>        public void DiscoverPlugins(string pluginDirectory)        {            if (!Directory.Exists(pluginDirectory))            {                Directory.CreateDirectory(pluginDirectory);                return;            }                        var pluginFiles = Directory.GetFiles(pluginDirectory, "*.dll");            foreach (var file in pluginFiles)            {                try                {                    var assembly = Assembly.LoadFrom(file);                    DiscoverPluginsFromAssembly(assembly);                }                catch (Exception ex)                {                    // 记录错误但继续处理其他插件                    Console.WriteLine($"加载插件文件 {file} 失败: {ex.Message}");                }            }        }                /// <summary>        /// 从程序集中发现插件        /// </summary>        /// <param name="assembly">程序集</param>        private void DiscoverPluginsFromAssembly(Assembly assembly)        {            var types = assembly.GetTypes();            foreach (var type in types)            {                if (typeof(IUIComponentPlugin).IsAssignableFrom(type) && !type.IsAbstract)                {                    try                    {                        var plugin = (IUIComponentPlugin)Activator.CreateInstance(type);                        RegisterPlugin(plugin);                    }                    catch (Exception ex)                    {                        Console.WriteLine($"创建插件实例失败: {ex.Message}");                    }                }            }        }                /// <summary>        /// 注册插件        /// </summary>        /// <param name="plugin">插件实例</param>        public void RegisterPlugin(IUIComponentPlugin plugin)        {            if (!_plugins.Contains(plugin))            {                plugin.Initialize(_context);                _plugins.Add(plugin);                                // 注册插件提供的组件                var componentTypes = plugin.GetComponentTypes();                if (componentTypes != null && componentTypes.Count > 0)                {                    if (!_componentRegistry.ContainsKey(plugin.Category))                    {                        _componentRegistry[plugin.Category] = new List<Type>();                    }                    _componentRegistry[plugin.Category].AddRange(componentTypes);                }            }        }                /// <summary>        /// 卸载所有插件        /// </summary>        public void UnloadAllPlugins()        {            foreach (var plugin in _plugins)            {                try                {                    plugin.Unload();                }                catch (Exception ex)                {                    Console.WriteLine($"卸载插件 {plugin.Name} 失败: {ex.Message}");                }            }            _plugins.Clear();            _componentRegistry.Clear();        }                /// <summary>        /// 获取指定分类的组件类型        /// </summary>        /// <param name="category">分类名称</param>        /// <returns>组件类型列表</returns>        public List<Type> GetComponentsByCategory(string category)        {            if (_componentRegistry.TryGetValue(category, out var types))            {                return types;            }            return new List<Type>();        }    }}